"use client";

import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";

export default function LoginPage() {
  const router = useRouter();
  const { loginAsUser, loginAsAdmin } = useAuth();

  return (
    <section className="section-wrapper" style={{ backgroundColor: "var(--color-bg)" }}>
      <div className="section-container" style={{ maxWidth: "520px" }}>
        <div style={{ textAlign: "center", marginBottom: "40px" }}>
          <span className="section-label">Access</span>
          <h1 className="section-heading" style={{ marginBottom: "16px" }}>
            Sign In
          </h1>
          <p style={{ fontSize: "14px", color: "var(--color-muted)" }}>
            Choose how you would like to continue. Only admins can access the Orders dashboard.
          </p>
        </div>

        <div
          className="surface"
          style={{
            borderRadius: "12px",
            padding: "28px 24px",
            display: "grid",
            gridTemplateColumns: "1fr",
            gap: "16px",
          }}
        >
          <button
            onClick={() => {
              loginAsUser();
              router.push("/");
            }}
            className="btn-outline"
            style={{ width: "100%" }}
          >
            Continue as Guest User
          </button>

          <button
            onClick={() => {
              loginAsAdmin();
              router.push("/orders");
            }}
            className="btn-gold"
            style={{ width: "100%" }}
          >
            Continue as Admin
          </button>
        </div>

        <p style={{ marginTop: "16px", fontSize: "12px", color: "var(--color-muted)", textAlign: "center" }}>
          This is a demo login. No real credentials are required.
        </p>
      </div>
    </section>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { Eye, EyeOff, Mail, Lock, UtensilsCrossed } from "lucide-react";

export default function CustomerLoginPage() {
  const router = useRouter();
  const { login } = useAuth();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    if (!email || !password) {
      setError("Please enter your email and password.");
      return;
    }

    setLoading(true);
    // Simulate async (would hit real auth endpoint in production)
    await new Promise((r) => setTimeout(r, 700));
    login("customer");
    router.push("/");
  };

  return (
    <div className="login-page">
      {/* Ambient glow blobs */}
      <div className="login-blob login-blob-1" />
      <div className="login-blob login-blob-2" />

      <motion.div
        initial={{ opacity: 0, y: 28 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7, ease: "easeOut" }}
        className="login-card"
      >
        {/* Logo */}
        <div className="login-logo">
          <div className="login-logo-circle">
            <UtensilsCrossed size={22} color="var(--color-gold)" />
          </div>
          <div>
            <p className="login-brand">Aurora Dining</p>
            <p className="login-brand-sub">Fine Dining Experience</p>
          </div>
        </div>

        {/* Divider */}
        <div className="login-divider" />

        {/* Heading */}
        <div className="login-header">
          <p className="login-eyebrow">Welcome Back</p>
          <h1 className="login-title">Customer Login</h1>
          <p className="login-subtitle">
            Sign in to manage your dining reservations
          </p>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="login-form" noValidate>
          {/* Email */}
          <div className="login-field">
            <label className="login-label">Email Address</label>
            <div className="login-input-wrap">
              <Mail size={15} className="login-input-icon" />
              <input
                id="customer-email"
                type="email"
                autoComplete="email"
                placeholder="your@email.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="login-input"
              />
            </div>
          </div>

          {/* Password */}
          <div className="login-field">
            <label className="login-label">Password</label>
            <div className="login-input-wrap">
              <Lock size={15} className="login-input-icon" />
              <input
                id="customer-password"
                type={showPw ? "text" : "password"}
                autoComplete="current-password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="login-input"
              />
              <button
                type="button"
                onClick={() => setShowPw(!showPw)}
                className="login-pw-toggle"
                aria-label="Toggle password visibility"
              >
                {showPw ? <EyeOff size={15} /> : <Eye size={15} />}
              </button>
            </div>
          </div>

          {/* Error */}
          {error && (
            <motion.p
              initial={{ opacity: 0, y: -6 }}
              animate={{ opacity: 1, y: 0 }}
              className="login-error"
            >
              {error}
            </motion.p>
          )}

          {/* Submit */}
          <motion.button
            type="submit"
            disabled={loading}
            whileHover={{ scale: loading ? 1 : 1.02 }}
            whileTap={{ scale: loading ? 1 : 0.98 }}
            className="login-btn"
          >
            {loading ? (
              <span className="login-spinner" />
            ) : (
              "Sign In"
            )}
          </motion.button>
        </form>

        {/* Footer note */}
        <p className="login-note">
          Staff or owner?{" "}
          <Link href="/admin-login" className="login-link">
            Admin Portal →
          </Link>
        </p>

        <div className="login-divider" style={{ marginTop: "28px" }} />
        <p className="login-hint">
          🍽 &nbsp;For reservations and dining enquiries
        </p>
      </motion.div>
    </div>
  );
}
